Author: Claude Fable 5 <noreply@anthropic.com>
Date:   Tue Jul 14 00:06:59 2026 +0100

    config: add PeerIdentities helper resolving effective per-peer PSK+name (T82)

    Add Config.PeerIdentities(), the single source for each configured WireGuard
    peer's effective outer-control PSK and stable name/id: a single-peer config
    resolves to the top-level Config.PSK (unaffected by any per-peer psk, the
    pre-G4 back-compat default); a multi-peer config resolves to each peer's own
    psk field. Name falls back to a short hex prefix of the peer's public key
    (mirroring uapiConfig's existing fallback) when peer.name is unset, so every
    identity has a non-empty, stable id. Order matches cfg.WireGuard.Peers.

    This centralizes the back-compat decision so device.Up and the Bind can
    consume it directly instead of each re-deriving it (no consumer wiring in
    this task — helper only).

    Add TestPeerIdentitiesSinglePeerUsesTopLevelPSK and
    TestPeerIdentitiesMultiPeerUsesOwnPSKAndName.
---
diff --git a/internal/config/config.go b/internal/config/config.go
index 763b543..dda8f7c 100644
--- a/internal/config/config.go
+++ b/internal/config/config.go
@@ -2,6 +2,7 @@ package config

 import (
 	"encoding/base64"
+	"encoding/hex"
 	"errors"
 	"fmt"
 	"math"
@@ -613,6 +614,47 @@ func validateHostname(host string) error {
 	return nil
 }

+// PeerIdentity is one configured WireGuard peer's effective outer-control PSK
+// and stable name/id (G4 multi-peer concentrator groundwork).
+type PeerIdentity struct {
+	// PSK is this peer's effective outer-control PSK: for a single-peer config
+	// it is the top-level Config.PSK (the pre-G4 back-compat default, unaffected
+	// by any per-peer psk); for a multi-peer config it is the peer's own PSK
+	// field.
+	PSK Key
+	// Name is this peer's stable identifier: its configured Name when set,
+	// otherwise a fallback derived from its public key (the first 8 bytes,
+	// lowercase hex — the same short-key form uapiConfig uses to name a peer
+	// in error messages), so every peer has a non-empty, stable id even when
+	// name is omitted.
+	Name string
+}
+
+// PeerIdentities returns, for each configured WireGuard peer in order, its
+// effective PSK and stable name/id (G4). This is the SINGLE place the
+// single-peer/multi-peer PSK back-compat decision is made: device.Up and the
+// Bind consume PeerIdentities instead of each re-deriving the effective PSK
+// from Config.PSK vs Peer.PSK. Order matches c.WireGuard.Peers.
+func (c Config) PeerIdentities() []PeerIdentity {
+	peers := c.WireGuard.Peers
+	ids := make([]PeerIdentity, len(peers))
+	for i, p := range peers {
+		psk := p.PSK
+		if len(peers) == 1 {
+			// Single-peer back-compat: the top-level psk remains the effective
+			// PSK regardless of whether a per-peer psk is also set.
+			psk = c.PSK
+		}
+		name := p.Name
+		if name == "" {
+			pub := p.PublicKey.Bytes()
+			name = hex.EncodeToString(pub[:8])
+		}
+		ids[i] = PeerIdentity{PSK: psk, Name: name}
+	}
+	return ids
+}
+
 // Amnezia holds the amneziawg-go obfuscation parameters. They must match on both
 // ends for the handshake to succeed; they are defense-in-depth only.
 //
diff --git a/internal/config/config_test.go b/internal/config/config_test.go
index d82ed6b..1c92c88 100644
--- a/internal/config/config_test.go
+++ b/internal/config/config_test.go
@@ -321,6 +321,74 @@ func TestLoadSinglePeerLegacyPSKGoldenShape(t *testing.T) {
 	}
 }

+// TestPeerIdentitiesSinglePeerUsesTopLevelPSK is the T82 single-peer back-compat
+// case: a single-peer config's PeerIdentities must report the top-level
+// Config.PSK as the effective PSK, and a stable fallback name/id since the
+// legacy fixture sets no per-peer name.
+func TestPeerIdentitiesSinglePeerUsesTopLevelPSK(t *testing.T) {
+	path := writeConfig(t, 0o600, fill(concentratorConfig))
+	c, err := Load(path)
+	if err != nil {
+		t.Fatalf("Load: %v", err)
+	}
+
+	ids := c.PeerIdentities()
+	if got := len(ids); got != 1 {
+		t.Fatalf("PeerIdentities() len = %d, want 1", got)
+	}
+	if ids[0].PSK.Bytes() != mustKey(t, 3).Bytes() {
+		t.Errorf("single-peer PeerIdentities()[0].PSK does not match top-level psk")
+	}
+	if ids[0].Name == "" {
+		t.Error("single-peer PeerIdentities()[0].Name must be non-empty (fallback id) when peer.name is unset")
+	}
+}
+
+// TestPeerIdentitiesMultiPeerUsesOwnPSKAndName is the T82 multi-peer case: each
+// peer's PeerIdentities entry must report that peer's OWN psk and name, in the
+// order matching cfg.WireGuard.Peers.
+func TestPeerIdentitiesMultiPeerUsesOwnPSKAndName(t *testing.T) {
+	r := strings.NewReplacer(
+		"%PRIV%", testKey(1),
+		"%PUB1%", testKey(2),
+		"%PSK%", testKey(3),
+		"%PUB2%", testKey(4),
+		"%PEERPSK1%", testKey(5),
+		"%PEERPSK2%", testKey(6),
+	)
+	body := r.Replace(twoPeerConcentratorConfig)
+	path := writeConfig(t, 0o600, body)
+	c, err := Load(path)
+	if err != nil {
+		t.Fatalf("Load: %v", err)
+	}
+
+	ids := c.PeerIdentities()
+	if got := len(ids); got != 2 {
+		t.Fatalf("PeerIdentities() len = %d, want 2", got)
+	}
+	// Order matches cfg.WireGuard.Peers.
+	if ids[0].Name != "edge-alpha" {
+		t.Errorf("PeerIdentities()[0].Name = %q, want %q", ids[0].Name, "edge-alpha")
+	}
+	if ids[1].Name != "edge-beta" {
+		t.Errorf("PeerIdentities()[1].Name = %q, want %q", ids[1].Name, "edge-beta")
+	}
+	if ids[0].PSK.Bytes() != mustKey(t, 5).Bytes() {
+		t.Errorf("PeerIdentities()[0].PSK does not match peer 0's own psk fixture value")
+	}
+	if ids[1].PSK.Bytes() != mustKey(t, 6).Bytes() {
+		t.Errorf("PeerIdentities()[1].PSK does not match peer 1's own psk fixture value")
+	}
+	if ids[0].PSK.Bytes() == ids[1].PSK.Bytes() {
+		t.Error("multi-peer PeerIdentities PSKs must be distinct per fixture, got equal")
+	}
+	// The top-level psk must NOT leak into a multi-peer identity.
+	if ids[0].PSK.Bytes() == mustKey(t, 3).Bytes() {
+		t.Error("multi-peer PeerIdentities()[0].PSK must not equal the top-level psk")
+	}
+}
+
